import React from "react";

const Platform = () => {
  return (
    <>
      <div>
        <h1>How it Works</h1>
        <h1>Platform & Mthodology</h1>
        <p>
          Advanced FinOps software combined with expert services to deliver sustainable cloud
          savings
        </p>

        <section>
            <ul>
                <p>Muti-cloud-visibility</p>
                <li>Unified dashboard across AWS, Azure, and GCP</li>
<li></li>Cost allocation by team, application, environment
<li></li>Real-time anomaly detection and alerts
            </ul>
        </section>


        
      </div>
    </>
  );
};

export default Platform;
